{{#switch:
  <!--If no or empty "demospace" parameter then detect namespace-->
  {{#if:{{{demospace|}}} 
  | {{lc: {{{demospace}}} }}    <!--Use lower case "demospace"-->
  | {{#ifeq:{{NAMESPACE}}|{{ns:0}}
    | main
    | other
    }} 
  }}
<!--If any parameter, then don't return the "main/other" strings-->
| main    = {{#if:{{{1|}}}{{{2|}}} | {{{1|}}} | main }}
| other
| #default = {{#if:{{{1|}}}{{{2|}}} | {{{2|}}} | other }} 

}}<!--End switch--><noinclude>

